ee:variables.ee:set-variable:
if(!isEmpty(attributes.queryParams.state))
(
	"SELECT COUNT(*) AS count, case_type, state
	 FROM covid_case_master WHERE state = '" 
	 ++ upper(attributes.queryParams.state) ++ 
	 "' GROUP BY case_type, state"
)else
(
		"SELECT COUNT(*) AS count, case_type, state FROM covid_case_master GROUP BY case_type, state"

)

ee:message.ee:set-payload:
%dw 2.0
output application/json

fun vaccinatedByState(state) 
    = (payload filter(($.state == state as String) 
	and ($.case_type == "vaccinated")) map {
	COUNT: $.count
})[0]

---
((payload groupBy ($.state)  mapObject {
 	caseReports: {
	state: $$,
	reports: {
		total : ($.count reduce $ + $$) - (vaccinatedByState($$).COUNT as Number default 0),
		($ orderBy($.case_type) map {
 				($.case_type): $.count
 			})

	}
	}
}).*caseReports) default []
